int minCarga(vector<int>& pesos, int numViajes) {
    // Definir el rango de búsqueda
    int izquierda = *max_element(pesos.begin(), pesos.end());
    int derecha = accumulate(pesos.begin(), pesos.end(), 0);

    // Búsqueda binaria
    while (izquierda < derecha) {
        int medio = izquierda + (derecha - izquierda) / 2;
        if (esPosible(pesos, numViajes, medio)) {
            derecha = medio;
        } else {
            izquierda = medio + 1;
        }
    }
    return izquierda;
}

